var isPublic=!!window.__PUBLIC_MODE__;var currentUser=window.__CURRENT_USER__||{name:'Owner admin',role:'Owner',homeView:'Dashboard',access:'Full platform access'};var db=normalize(window.__SERVER_DATA__||fallbackData);var nav=navForRole();var view=isPublic?'Apply':(currentUser.homeView||nav[0]||'Dashboard');var tab='Board';var stages=['New','Docs needed','Approved','Contract'];var root=document.getElementById('root');var LIVE_REFRESH_MS=10000;var API_AUTO_SYNC_MS=60000;var syncInFlight=false;var lastApiAutoSync=Number(localStorage.getItem('woa-last-api-auto-sync')||0);
function navForRole(){var r=String((currentUser&&currentUser.role)||'Owner').toLowerCase();if(r==='mechanic')return['Mechanic Portal','Maintenance','Fleet','Messages'];if(r==='manager')return['Manager Portal','Today','Customers','Applications','Fleet','Maintenance','Claims & Issues','Messages','Reports'];return['Dashboard','Today','Customers','Payments','Applications','Fleet','Maintenance','Claims & Issues','Mechanic Portal','Manager Portal','Messages','Reports','Companies','API Roadmap','Settings']}
function normalize(d){d=Object.assign({},fallbackData,d||{});d.integrations=Object.assign({},fallbackData.integrations,d.integrations||{});d.integrations.clover=Object.assign({},fallbackData.integrations.clover,d.integrations.clover||{});d.integrations.shopify=Object.assign({},fallbackData.integrations.shopify,d.integrations.shopify||{});d.vehicles=(d.vehicles||[]).map(function(v,i){var p=(v.name||'').split(' ');v.id=v.id||'veh-'+i;v.year=v.year||p[0]||'';v.make=v.make||p[1]||'';v.model=v.model||p.slice(2).join(' ')||'';v.price=v.price||((v.rate||229)*110);v.mileage=v.mileage||v.odometer||0;v.stock=v.stock||v.plate||('STK-'+(i+1));v.status=v.status==='Available'?'Ready':(v.status||'Ready');return v});d.applications=(d.applications||[]).map(function(a,i){var st=a.stage||a.status||'New';if(st==='Needs review')st='New';if(st==='Docs requested')st='Docs needed';a.id=a.id||'app-'+i;a.name=a.name||a.customer||'Applicant';a.stage=st;a.status=st;a.down=Number(a.down==null?0:a.down);a.income=Number(a.income)||0;a.score=a.score||estimate(a.income,a.down);a.submittedAt=a.submittedAt||a.date||'Today';return a});return d}
function esc(v){return String(v==null?'':v).replace(/[&<>"]/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]})}function money(n){return '$'+Number(n||0).toLocaleString()}function val(id){return document.getElementById(id)?document.getElementById(id).value:''}function now(){return new Date().toLocaleString([], {month:'short',day:'numeric',hour:'numeric',minute:'2-digit'})}function estimate(income,down){var s=45;if(income>=2500)s+=20;if(income>=4000)s+=10;if(down>=1000)s+=15;if(down>=2000)s+=10;return Math.min(98,s)}function vehicleName(v){return [v.year,v.make,v.model].filter(Boolean).join(' ')||v.name||'Vehicle'}function isInventoryVehicle(v){var s=String(v.status||'').toLowerCase();return !normName(v.currentCustomer)&&s!=='rented'&&s!=='removed'}
function tone(s){if(['Active','Approved','Ready','Paid','Received','Submitted','Connected'].indexOf(s)>=0)return'good';if(['Docs needed','Due','Scheduled','Setup needed','Review','Pending pickup','New'].indexOf(s)>=0)return'warn';if(['Failed','Failed retry','Not connected','Maintenance'].indexOf(s)>=0)return'bad';return'blue'}function badge(s,t){return '<span class="tag '+(t||tone(s))+'">'+esc(s)+'</span>'}function notify(m){var t=document.getElementById('toast');t.textContent=m;t.classList.add('show');setTimeout(function(){t.classList.remove('show')},2400)}
